revision.text:
/* {{pp-template}} */
.hidden-begin {
	box-sizing: border-box;
	width: 100%;
	padding: 5px;
	border: none;
	font-size: 95%;
}

.hidden-title {
	font-weight: bold;
	line-height: 1.6;
	text-align: left;
}

.hidden-content {
	text-align: left;
}

/* [[phab:T360582]] */
@media all and ( max-width: 500px ) {
  .hidden-begin {
    width: auto !important;
    clear: none  !important;
    float: none !important;
  }
}

